/* ---------- ROI calculator ---------- */
function ROI() {
  const [missed, setMissed] = useState(12);
  const [lostPct, setLostPct] = useState(30);
  const [fee, setFee] = useState(65);
  const lostPerMonth = Math.round(missed * (lostPct / 100) * fee * 22);
  const cost = 449;
  const net = lostPerMonth - cost;
  return (
    <section className="sec" id="roi">
      <div className="wrap">
        <Reveal>
          <Eyebrow>What the engaged tone costs</Eyebrow>
          <h2>Run your own numbers</h2>
        </Reveal>
        <Reveal delay={120}>
          <div className="roi">
            <div className="roi-controls">
              <label>
                <span>Missed calls per day <b>{missed}</b></span>
                <input type="range" min="2" max="40" value={missed} onChange={(e) => setMissed(+e.target.value)} />
              </label>
              <label>
                <span>% who book elsewhere <b>{lostPct}%</b></span>
                <input type="range" min="10" max="60" step="5" value={lostPct} onChange={(e) => setLostPct(+e.target.value)} />
              </label>
              <label>
                <span>Average visit fee <b>€{fee}</b></span>
                <input type="range" min="45" max="90" step="5" value={fee} onChange={(e) => setFee(+e.target.value)} />
              </label>
            </div>
            <div className="roi-out">
              <div className="roi-row"><span>Revenue walking out the door</span><b className="loss">€{lostPerMonth.toLocaleString()}/mo</b></div>
              <div className="roi-row"><span>Eirim Front Desk</span><b>€{cost}/mo</b></div>
              <div className="roi-row roi-net"><span>Recovered every month</span><b className="gain">€{Math.max(net, 0).toLocaleString()}</b></div>
              <p className="roi-fn">22 clinic days/month. Excludes receptionist hours freed and fewer no-shows from SMS confirmations.</p>
            </div>
          </div>
        </Reveal>
      </div>
    </section>
  );
}

